package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.provider.Settings
import android.util.Log
import android.widget.Button
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG
import androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_WEAK
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

// --- SharedPreferences Manager ---
object SharedPreferencesManager {
    private const val PREFS_NAME = "app_prefs"
    private const val KEY_AUTHENTICATED = "is_authenticated"

    fun setAuthenticated(context: Context, isAuthenticated: Boolean) {
        val sharedPrefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        with(sharedPrefs.edit()) {
            putBoolean(KEY_AUTHENTICATED, isAuthenticated)
            apply()
        }
    }

    fun isAuthenticated(context: Context): Boolean {
        val sharedPrefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        return sharedPrefs.getBoolean(KEY_AUTHENTICATED, false)
    }

    fun clearAuthentication(context: Context) {
        val sharedPrefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        with(sharedPrefs.edit()) {
            remove(KEY_AUTHENTICATED)
            apply()
        }
    }
}

// --- MainActivity (Welcome Screen) ---
class MainActivity : AppCompatActivity() {

    private lateinit var welcomeTextView: TextView
    private lateinit var logoutButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main) // You'll need to create this layout

        welcomeTextView = findViewById(R.id.welcomeTextView)
        logoutButton = findViewById(R.id.logoutButton)

        welcomeTextView.text = "Welcome! You are authenticated."

        logoutButton.setOnClickListener {
            SharedPreferencesManager.clearAuthentication(this)
            Toast.makeText(this, "Logged out", Toast.LENGTH_SHORT).show()
            val intent = Intent(this, LoginActivity::class.java)
            startActivity(intent)
            finish()
        }
    }
}

// --- LoginActivity (Handles Biometric and Fallback) ---
class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var statusTextView: TextView
    private lateinit var passwordLoginButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login) // You'll need to create this layout

        statusTextView = findViewById(R.id.statusTextView)
        passwordLoginButton = findViewById(R.id.passwordLoginButton)

        // Check if already authenticated
        if (SharedPreferencesManager.isAuthenticated(this)) {
            navigateToMainActivity()
            return
        }

        passwordLoginButton.setOnClickListener {
            // In a real app, this would navigate to a password/PIN entry screen
            Toast.makeText(this, "Navigating to Password Login...", Toast.LENGTH_SHORT).show()
            statusTextView.text = "Please enter your password."
            // For this example, we'll just simulate success after password login
            // and then navigate to MainActivity
            // SharedPreferencesManager.setAuthenticated(this, true)
            // navigateToMainActivity()
        }

        setupBiometricPrompt()
        checkBiometricAvailability()
    }

    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Log.e("BiometricAuth", "Authentication error: $errString (Code: $errorCode)")
                    statusTextView.text = "Biometric error: $errString"
                    Toast.makeText(applicationContext, "Authentication error: $errString", Toast.LENGTH_SHORT).show()

                    when (errorCode) {
                        BiometricPrompt.ERROR_NO_BIOMETRICS,
                        BiometricPrompt.ERROR_HW_UNAVAILABLE,
                        BiometricPrompt.ERROR_NO_DEVICE_CREDENTIAL,
                        BiometricPrompt.ERROR_LOCKOUT,
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT,
                        BiometricPrompt.ERROR_USER_CANCELED -> {
                            // These errors usually mean biometrics can't be used right now or user cancelled.
                            // Fallback to password login.
                            showPasswordLoginFallback()
                        }
                        else -> {
                            // Other errors might allow retrying biometric or also fallback
                            showPasswordLoginFallback()
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Log.d("BiometricAuth", "Authentication succeeded!")
                    statusTextView.text = "Authentication Succeeded!"
                    Toast.makeText(applicationContext, "Authentication Succeeded!", Toast.LENGTH_SHORT).show()
                    SharedPreferencesManager.setAuthenticated(this@LoginActivity, true)
                    navigateToMainActivity()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Log.w("BiometricAuth", "Authentication failed.")
                    statusTextView.text = "Authentication Failed. Try again."
                    Toast.makeText(applicationContext, "Authentication Failed. Try again.", Toast.LENGTH_SHORT).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Log in using your fingerprint or face")
            .setDescription("Place your finger on the sensor or look at the camera to authenticate.")
            // This is the fallback button. If clicked, onAuthenticationError with ERROR_USER_CANCELED is called.
            .setNegativeButtonText("Use Password")
            .setAllowedAuthenticators(BIOMETRIC_STRONG or BIOMETRIC_WEAK) // Use BIOMETRIC_STRONG for stronger security
            .build()
    }

    private fun checkBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BIOMETRIC_STRONG or BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                Log.d("BiometricAuth", "Biometric features are available.")
                statusTextView.text = "Biometric available. Please authenticate."
                passwordLoginButton.visibility = Button.GONE // Hide password button initially
                biometricPrompt.authenticate(promptInfo)
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Log.e("BiometricAuth", "No biometric features available on this device.")
                statusTextView.text = "No biometric hardware found."
                showPasswordLoginFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Log.e("BiometricAuth", "Biometric features are currently unavailable.")
                statusTextView.text = "Biometric hardware unavailable."
                showPasswordLoginFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                Log.e("BiometricAuth", "No biometric credentials enrolled.")
                statusTextView.text = "No biometrics enrolled. Please enroll in settings."
                showPasswordLoginFallback()
                // Optionally, prompt user to enroll biometrics
                val enrollIntent = Intent(Settings.ACTION_BIOMETRIC_ENROLL).apply {
                    putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED, BIOMETRIC_STRONG or BIOMETRIC_WEAK)
                }
                startActivity(enrollIntent)
            }
            else -> {
                Log.e("BiometricAuth", "Unknown biometric error.")
                statusTextView.text = "Unknown biometric error."
                showPasswordLoginFallback()
            }
        }
    }

    private fun showPasswordLoginFallback() {
        statusTextView.text = "Biometric authentication not available or failed. Please use password."
        passwordLoginButton.visibility = Button.VISIBLE
    }

    private fun navigateToMainActivity() {
        val intent = Intent(this, MainActivity::class.java)
        startActivity(intent)
        finish() // Prevent going back to LoginActivity
    }
}

